import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import * as LucideIcons from 'lucide-react';
import { getNavItemsForRole } from '../../config/navigation';
import type { UserRole, AppPage } from '../../types';

interface AppLayoutProps {
  activePage: AppPage;
  onNavigate: (page: AppPage) => void;
  userRole: UserRole;
  userName: string;
  children: React.ReactNode;
}

function getLucideIcon(name: string): React.ElementType<any> {
  const icons = LucideIcons as unknown as Record<string, React.ElementType<any>>;
  return icons[name] || LucideIcons.Circle;
}

export const AppLayout: React.FC<AppLayoutProps> = ({
  activePage,
  onNavigate,
  userRole,
  userName,
  children,
}) => {
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  const navItems = getNavItemsForRole(userRole);
  const userInitial = userName.charAt(0).toUpperCase();

  return (
    <div className="flex h-screen bg-zinc-950 text-white overflow-hidden">
      {/* ─── Sidebar ─── */}
      <aside
        className={`
          fixed md:relative z-50 h-screen flex flex-col
          bg-surface-50 border-r border-white/[0.06]
          transition-all duration-300 ease-in-out
          ${sidebarCollapsed ? 'w-[72px]' : 'w-[260px]'}
          ${mobileMenuOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
        `}
      >
        {/* Logo Area */}
        <div className={`flex items-center border-b border-white/[0.06] ${sidebarCollapsed ? 'justify-center px-3 py-5' : 'px-5 py-5'}`}>
          <div className="flex items-center gap-2.5">
            <div className="w-9 h-9 rounded-lg bg-white/10 flex items-center justify-center flex-shrink-0">
              <LucideIcons.GraduationCap className="w-5 h-5 text-white" />
            </div>
            {!sidebarCollapsed && (
              <motion.div
                initial={{ opacity: 0, width: 0 }}
                animate={{ opacity: 1, width: 'auto' }}
                exit={{ opacity: 0, width: 0 }}
                className="overflow-hidden"
              >
                <h1 className="text-lg font-bold text-white leading-none">Campusly</h1>
              </motion.div>
            )}
          </div>
        </div>

        {/* User Card */}
        <div className={`border-b border-white/[0.06] ${sidebarCollapsed ? 'px-3 py-4' : 'px-4 py-4'}`}>
          <div className={`flex items-center ${sidebarCollapsed ? 'justify-center' : 'gap-3'}`}>
            <div className="w-9 h-9 rounded-full bg-white/10 border border-white/10 flex items-center justify-center text-sm font-semibold text-white flex-shrink-0">
              {userInitial}
            </div>
            {!sidebarCollapsed && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="overflow-hidden min-w-0"
              >
                <p className="text-sm font-semibold text-white truncate">{userName}</p>
                <p className="text-xs text-white/50 capitalize">{userRole}</p>
              </motion.div>
            )}
          </div>
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto py-3 px-2.5 space-y-0.5">
          {navItems.map((item) => {
            const Icon = getLucideIcon(item.icon);
            const isActive = activePage === item.id;

            return (
              <button
                key={item.id}
                onClick={() => {
                  onNavigate(item.id);
                  setMobileMenuOpen(false);
                }}
                className={`
                  w-full flex items-center gap-3 rounded-lg transition-all duration-200
                  ${sidebarCollapsed ? 'justify-center px-2 py-2.5' : 'px-3 py-2.5'}
                  ${isActive
                    ? 'bg-white/10 text-white font-semibold'
                    : 'text-white/50 hover:bg-white/[0.04] hover:text-white/80'
                  }
                `}
                title={sidebarCollapsed ? item.label : undefined}
              >
                <Icon className={`w-[18px] h-[18px] flex-shrink-0 ${isActive ? 'text-white' : 'text-white/35'}`} />
                {!sidebarCollapsed && (
                  <span className="text-[13px] truncate">{item.label}</span>
                )}
                {isActive && !sidebarCollapsed && (
                  <div className="ml-auto w-1.5 h-1.5 rounded-full bg-white" />
                )}
              </button>
            );
          })}
        </nav>

        {/* Collapse Toggle (desktop) */}
        <div className="hidden md:flex border-t border-white/[0.06] px-2.5 py-3">
          <button
            onClick={() => setSidebarCollapsed(!sidebarCollapsed)}
            className="w-full flex items-center justify-center gap-2 px-3 py-2 rounded-lg text-white/35 hover:text-white/60 hover:bg-white/[0.04] transition-all duration-200"
          >
            {sidebarCollapsed ? (
              <LucideIcons.PanelRightOpen className="w-[18px] h-[18px]" />
            ) : (
              <>
                <LucideIcons.PanelLeftOpen className="w-[18px] h-[18px]" />
                <span className="text-xs">Collapse</span>
              </>
            )}
          </button>
        </div>
      </aside>

      {/* ─── Main Area ─── */}
      <div className="flex-1 flex flex-col overflow-hidden">
        {/* Top Bar */}
        <header className="flex items-center justify-between px-4 md:px-6 py-3.5 bg-surface-50 border-b border-white/[0.06]">
          {/* Left: mobile menu + page title */}
          <div className="flex items-center gap-3">
            <button
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className="md:hidden p-2 -ml-2 rounded-lg hover:bg-white/[0.06] transition-colors"
            >
              <LucideIcons.Menu className="w-5 h-5 text-white/60" />
            </button>
            <div>
              <h2 className="text-lg font-semibold text-white">
                {navItems.find(item => item.id === activePage)?.label || 'Dashboard'}
              </h2>
            </div>
          </div>

          {/* Right: search + notifications */}
          <div className="flex items-center gap-2">
            <button 
              onClick={() => alert('Search functionality coming soon!')}
              className="p-2 rounded-lg hover:bg-white/[0.06] transition-colors"
            >
              <LucideIcons.Search className="w-[18px] h-[18px] text-white/45" />
            </button>
            <button 
              onClick={() => alert('You have no new notifications.')}
              className="p-2 rounded-lg hover:bg-white/[0.06] transition-colors relative"
            >
              <LucideIcons.Bell className="w-[18px] h-[18px] text-white/45" />
              <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-accent rounded-full" />
            </button>
          </div>
        </header>

        {/* Content */}
        <main className="flex-1 overflow-y-auto bg-surface">
          <div className="p-4 md:p-6 lg:p-8 max-w-7xl mx-auto w-full">
            <AnimatePresence mode="wait">
              <motion.div
                key={activePage}
                initial={{ opacity: 0, y: 12 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -12 }}
                transition={{ duration: 0.2 }}
              >
                {children}
              </motion.div>
            </AnimatePresence>
          </div>
        </main>
      </div>

      {/* Mobile Overlay */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setMobileMenuOpen(false)}
            className="fixed inset-0 bg-black/50 md:hidden z-40"
          />
        )}
      </AnimatePresence>
    </div>
  );
};

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { 
  Loader2, 
  ShieldCheck, 
  Trash2, 
  UserPlus, 
  FileEdit, 
  Calendar, 
  X,
  Activity,
  Users,
  Clock,
  ExternalLink
} from 'lucide-react';
import { Link } from 'react-router-dom';
import { useApi } from '../../hooks/useApi';
import * as api from '../../lib/api';

export const Admin: React.FC = () => {
  const [roleFilter, setRoleFilter] = useState('');

  // Modal States
  const [isUserModalOpen, setIsUserModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<any>(null);

  // Data Fetching
  const { data: usersData, isLoading: isLoadingUsers, refetch: refetchUsers } = useApi(() => api.fetchUsers(roleFilter ? { role: roleFilter } : undefined), [roleFilter]);
  const { data: dashData, refetch: refetchDash } = useApi(() => api.fetchDashboard(), []);
  const { data: marketData, refetch: refetchMarket } = useApi(() => api.fetchPendingMarketplaceItems(), []);
  const { data: requestsData, refetch: refetchRequests } = useApi(() => api.fetchPendingRequests(), []);
  const { data: recentEventsData } = useApi(() => api.fetchEvents(), []);

  const [isDeleting, setIsDeleting] = useState<string | null>(null);

  const handleDeleteUser = async (id: string) => {
    if (!window.confirm('Are you sure you want to delete this user?')) return;
    setIsDeleting(id);
    try {
      await api.deleteUser(id);
      refetchUsers();
    } catch (err: any) {
      alert(err.message || 'Failed to delete user');
    } finally {
      setIsDeleting(null);
    }
  };

  const stats = dashData?.stats || {};
  const pendingActionsCount = (marketData?.items?.length || 0) + (requestsData?.requests?.length || 0);

  const adminStats = [
    { label: 'Total Users', value: stats.totalUsers || '—', icon: <Users className="w-5 h-5" />, color: 'text-white' },
    { label: 'Active Events', value: stats.totalEvents || '—', icon: <Calendar className="w-5 h-5" />, color: 'text-white' },
    { label: 'Pending Actions', value: pendingActionsCount, icon: <Activity className="w-5 h-5 text-amber-500" />, color: 'text-amber-500' },
    { label: 'System Status', value: 'ONLINE', icon: <ShieldCheck className="w-5 h-5 text-emerald-500" />, color: 'text-emerald-500' },
  ];

  return (
    <div className="space-y-10">
      {/* Header & Quick Status */}
      <div className="flex flex-col md:flex-row md:items-end justify-between gap-6">
        <div>
          <h1 className="text-5xl font-bold text-white tracking-tighter">Command Center</h1>
          <p className="text-white/40 mt-2 text-lg">Absolute oversight of campus operations</p>
        </div>

        <div className="flex gap-4">
          <Link to="/requests" className="flex items-center gap-2 px-4 py-2 rounded-lg bg-white/[0.03] border border-white/5 hover:bg-white/[0.06] transition-all group">
            <span className="text-[10px] uppercase font-bold text-white/40 group-hover:text-white">Moderation Queue</span>
            <ExternalLink className="w-3 h-3 text-white/20" />
          </Link>
          <button 
            onClick={() => { setEditingUser(null); setIsUserModalOpen(true); }}
            className="bg-white text-black px-6 py-2.5 rounded-lg text-xs font-black shadow-xl hover:bg-zinc-200 transition-all flex items-center gap-2 hover:scale-[1.02] active:scale-[0.98]"
          >
            <UserPlus className="w-4 h-4" />
            CREATE NEW USER
          </button>
        </div>
      </div>

      {/* Hero Pulse Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        {adminStats.map((stat) => (
          <motion.div
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.05 }}
            className="card-dark p-8 border-white/[0.03] hover:border-white/[0.08] transition-all relative overflow-hidden group"
          >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
              {stat.icon}
            </div>
            <p className="text-white/30 text-[10px] uppercase font-bold tracking-[0.2em] mb-4">{stat.label}</p>
            <p className={`text-4xl font-extralight tracking-tighter ${stat.color}`}>
              {stat.value}
            </p>
          </motion.div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main User Control Table */}
        <div className="lg:col-span-2 space-y-4">
          <div className="flex items-center justify-between mb-2">
            <h2 className="text-sm font-bold uppercase tracking-widest text-white/60">User Directory</h2>
            <select
              value={roleFilter}
              onChange={(e) => setRoleFilter(e.target.value)}
              className="bg-zinc-950 border border-white/10 text-white/40 text-[10px] uppercase font-bold px-3 py-1.5 rounded-lg focus:outline-none focus:border-white/30 transition-all cursor-pointer"
            >
              <option value="">All Roles</option>
              <option value="student">Students</option>
              <option value="faculty">Faculty</option>
              <option value="alumni">Alumni</option>
              <option value="admin">Administrators</option>
            </select>
          </div>

          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="card-dark overflow-hidden border-white/[0.04]"
          >
            {isLoadingUsers ? (
              <div className="p-20 flex justify-center"><Loader2 className="w-8 h-8 animate-spin text-white/10" /></div>
            ) : (
              <table className="w-full text-left">
                <thead className="text-[10px] uppercase font-black tracking-widest text-white/20 border-b border-white/[0.03]">
                  <tr>
                    <th className="py-6 px-6">Identity</th>
                    <th className="py-6 px-4">Clearance</th>
                    <th className="py-6 px-4">Contact / Depth</th>
                    <th className="py-6 px-6 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/[0.02]">
                  {usersData?.users?.map((u: any) => (
                    <tr key={u.id} className="group hover:bg-white/[0.01] transition-all">
                      <td className="py-5 px-6">
                        <div className="flex flex-col">
                          <span className="text-sm font-semibold text-white/90 group-hover:text-white">{u.fullName}</span>
                          <span className="text-xs text-white/30 font-mono tracking-tighter mt-0.5">{u.email}</span>
                        </div>
                      </td>
                      <td className="py-5 px-4">
                        <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-white/5 ${
                          u.role === 'admin' ? 'text-white border-white/20 bg-white/5' : 'text-white/40'
                        }`}>
                          {u.role}
                        </span>
                      </td>
                      <td className="py-5 px-4">
                        <div className="flex flex-col">
                          <span className="text-[10px] text-white/50">{u.department || 'N/A'}</span>
                          {u.company && (
                            <span className="text-[10px] text-white/20 uppercase font-bold tracking-tighter mt-1">
                              @ {u.company} · {u.position}
                            </span>
                          )}
                        </div>
                      </td>
                      <td className="py-5 px-6 text-right">
                        <div className="flex items-center gap-4 justify-end opacity-20 group-hover:opacity-100 transition-opacity">
                          <button 
                            onClick={() => { setEditingUser(u); setIsUserModalOpen(true); }}
                            className="text-white hover:scale-110 transition-all"
                          >
                            <FileEdit className="w-4 h-4" />
                          </button>
                          <button 
                            onClick={() => handleDeleteUser(u.id)}
                            disabled={isDeleting === u.id}
                            className="text-white hover:text-red-500 hover:scale-110 transition-all"
                          >
                            {isDeleting === u.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Trash2 className="w-4 h-4" />}
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </motion.div>
        </div>

        {/* System Pulse / Recent Activity */}
        <div className="space-y-4">
          <h2 className="text-sm font-bold uppercase tracking-widest text-white/60 mb-2">System Pulse</h2>

          <div className="card-dark p-6 space-y-6 border-white/[0.04] h-fit">
            <div className="space-y-4">
              <div className="flex items-center justify-between text-[10px] font-bold text-white/30 uppercase tracking-widest">
                <span>Recent Events</span>
                <Link to="/events" className="hover:text-white transition-colors">Manage All</Link>
              </div>
              <div className="space-y-3">
                {recentEventsData?.events?.slice(0, 3).map((e: any) => (
                  <div key={e.id} className="flex items-center gap-3 group translate-z-0">
                    <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center flex-shrink-0 group-hover:bg-white/10 transition-colors">
                      <Calendar className="w-4 h-4 text-white/20" />
                    </div>
                    <div className="flex-1 min-w-0">
                      <p className="text-xs font-semibold text-white/80 truncate group-hover:text-white transition-colors">{e.title}</p>
                      <p className="text-[10px] text-white/20">{new Date(e.startsAt).toLocaleDateString()}</p>
                    </div>
                  </div>
                )) || <p className="text-[10px] text-white/20 italic">No recent events recorded</p>}
              </div>
            </div>

            <div className="h-px bg-white/[0.04]" />

            <div className="space-y-4">
              <div className="flex items-center justify-between text-[10px] font-bold text-white/30 uppercase tracking-widest">
                <span>Pending Approvals</span>
                <Link to="/requests" className="hover:text-white transition-colors">Review Queue</Link>
              </div>
              <div className="space-y-3">
                {requestsData?.requests?.length === 0 ? (
                  <p className="text-[10px] text-white/20 italic">No pending requests</p>
                ) : (
                  requestsData?.requests?.slice(0, 3).map((req: any) => (
                    <div key={req.id} className="p-3 rounded-xl bg-white/[0.02] border border-white/[0.05] hover:border-white/10 transition-all flex items-center justify-between gap-3 group">
                      <div className="flex items-center gap-3 min-w-0">
                        <div className="w-8 h-8 rounded-lg bg-white/5 flex items-center justify-center flex-shrink-0">
                          <Clock className="w-4 h-4 text-amber-500/40" />
                        </div>
                        <div className="flex-1 min-w-0">
                          <p className="text-xs font-semibold text-white/80 truncate group-hover:text-white transition-colors">{req.title || req.type}</p>
                          <p className="text-[10px] text-white/20 uppercase tracking-widest">{req.studentName}</p>
                        </div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={async () => {
                            await api.updateRequestStatus(req.id, 'processing');
                            refetchRequests();
                            refetchDash();
                          }}
                          className="p-1 px-2 rounded bg-white text-black text-[8px] font-black uppercase hover:bg-zinc-200"
                        >
                          Process
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>

            <div className="h-px bg-white/[0.04]" />

            <div className="space-y-4">
              <div className="flex items-center justify-between text-[10px] font-bold text-white/30 uppercase tracking-widest">
                <span>Marketplace Activity</span>
                <Link to="/app/marketplace" className="hover:text-white transition-colors">Moderate</Link>
              </div>
              <div className="space-y-3">
                {marketData?.items?.length === 0 ? (
                  <p className="text-[10px] text-white/20 italic">No pending marketplace items</p>
                ) : (
                  marketData?.items?.slice(0, 5).map((item: any) => (
                    <div key={item.id} className="p-3 rounded-xl bg-white/[0.02] border border-white/[0.05] hover:border-white/10 transition-all flex items-center justify-between gap-3 group">
                      <div className="flex items-center gap-3 min-w-0">
                        <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center flex-shrink-0 text-xl">
                          {item.image || '📦'}
                        </div>
                        <div className="min-w-0">
                          <p className="text-xs font-semibold text-white/80 truncate group-hover:text-white transition-colors">{item.title}</p>
                          <p className="text-[10px] text-white/20 uppercase tracking-widest mt-0.5">₹{item.price} · {item.seller}</p>
                        </div>
                      </div>
                      <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                        <button 
                          onClick={async () => {
                            await api.updateMarketplaceItemStatus(item.id, 'approved');
                            refetchMarket();
                            refetchDash();
                          }}
                          className="p-1 px-2 rounded bg-white text-black text-[8px] font-black uppercase hover:bg-zinc-200 transition-all"
                        >
                          Approve
                        </button>
                        <button 
                          onClick={async () => {
                            await api.updateMarketplaceItemStatus(item.id, 'rejected');
                            refetchMarket();
                            refetchDash();
                          }}
                          className="p-1 px-2 rounded border border-white/10 text-white/40 text-[8px] font-black uppercase hover:bg-white/5 transition-all"
                        >
                          Reject
                        </button>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* User Management Modal */}
      {isUserModalOpen && (
        <UserModal 
          user={editingUser} 
          onClose={() => setIsUserModalOpen(false)} 
          onSave={() => { setIsUserModalOpen(false); refetchUsers(); }} 
        />
      )}
    </div>
  );
};

// ─── User Management Modal ───

const UserModal = ({ user, onClose, onSave }: any) => {
  const [formData, setFormData] = useState({
    email: user?.email || '',
    fullName: user?.fullName || '',
    password: '',
    role: user?.role || 'student',
    department: user?.department || '',
    phone: user?.phone || '',
    company: user?.company || '',
    position: user?.position || '',
  });
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      if (user) {
        const { password, ...updateData } = formData;
        if (!password) delete (updateData as any).password;
        await api.updateUser(user.id, updateData);
      } else {
        await api.createUser(formData);
      }
      onSave();
    } catch (err: any) {
      alert(err.message || 'Failed to save user');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-black/95 backdrop-blur-xl">
      <motion.div initial={{ scale: 0.95, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-zinc-900 border border-white/10 rounded-2xl w-full max-w-lg p-10 shadow-2xl overflow-hidden relative">
        <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-white/10 to-transparent" />

        <div className="flex justify-between items-center mb-10">
          <div>
            <h2 className="text-2xl font-bold text-white tracking-tight">{user ? 'Refine Profile' : 'Initialize Identity'}</h2>
            <p className="text-[10px] uppercase font-black tracking-widest text-white/20 mt-1">{user ? 'Update access credentials' : 'Deploy new campus access'}</p>
          </div>
          <button onClick={onClose} className="text-white/20 hover:text-white p-2 transition-colors"><X className="w-6 h-6" /></button>
        </div>

        <form onSubmit={handleSubmit} className="space-y-6">
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Registry Name</label>
              <input 
                value={formData.fullName} 
                onChange={e => setFormData({...formData, fullName: e.target.value})} 
                className="input-dark text-sm w-full py-3" required 
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Network Email</label>
              <input 
                type="email" 
                value={formData.email} 
                onChange={e => setFormData({...formData, email: e.target.value})} 
                className="input-dark text-sm w-full py-3" required 
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Security Clearance (Role)</label>
              <select 
                value={formData.role} 
                onChange={e => setFormData({...formData, role: e.target.value})} 
                className="input-dark text-sm w-full py-3 appearance-none cursor-pointer"
              >
                <option value="student">Student</option>
                <option value="faculty">Faculty</option>
                <option value="admin">Administrator</option>
                <option value="alumni">Alumni</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Security Code (Password)</label>
              <input 
                type="password" 
                placeholder={user ? "Leave blank to keep current" : "Set initial password"}
                value={formData.password} 
                onChange={e => setFormData({...formData, password: e.target.value})} 
                className="input-dark text-sm w-full py-3" 
                required={!user}
              />
            </div>
          </div>

          <div className="h-px bg-white/5 my-4" />

          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Department Zone</label>
              <input 
                value={formData.department} 
                onChange={e => setFormData({...formData, department: e.target.value})} 
                className="input-dark text-sm w-full py-3" 
                placeholder="N/A"
              />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Primary Comm (Phone)</label>
              <input 
                value={formData.phone} 
                onChange={e => setFormData({...formData, phone: e.target.value})} 
                className="input-dark text-sm w-full py-3" 
                placeholder="+91..."
              />
            </div>
          </div>

          {formData.role === 'alumni' && (
            <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} className="grid grid-cols-2 gap-6 border-t border-white/5 pt-6">
              <div className="space-y-2">
                <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Industry Anchor (Company)</label>
                <input 
                  value={formData.company} 
                  onChange={e => setFormData({...formData, company: e.target.value})} 
                  className="input-dark text-sm w-full py-3" 
                />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] uppercase font-black tracking-widest text-white/30">Deployment (Position)</label>
                <input 
                  value={formData.position} 
                  onChange={e => setFormData({...formData, position: e.target.value})} 
                  className="input-dark text-sm w-full py-3" 
                />
              </div>
            </motion.div>
          )}

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-white text-black py-4 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-zinc-200 transition-all flex justify-center mt-10 shadow-2xl hover:scale-[1.02] active:scale-[0.98]"
          >
            {loading ? <Loader2 className="w-5 h-5 animate-spin" /> : user ? 'COMMIT PROFILE UPDATE' : 'INITIALIZE USER ACCESS'}
          </button>
        </form>
      </motion.div>
    </div>
  );
};

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
  Search,
  Users,
  Briefcase,
  MessageSquare,
  Loader2,
  AlertTriangle,
} from 'lucide-react';
import { useApi } from '../../hooks/useApi';
import * as api from '../../lib/api';

export function AlumniNetwork() {
  const [search, setSearch] = useState('');
  const { data, isLoading, error } = useApi(() => api.fetchAlumni(), []);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-accent-light animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-white/60 gap-3">
        <AlertTriangle className="w-8 h-8 text-amber-400" />
        <p className="text-sm">{error}</p>
      </div>
    );
  }

  const alumni = data?.alumni || [];
  const filtered = !search
    ? alumni
    : alumni.filter(
        (a: any) =>
          a.name?.toLowerCase().includes(search.toLowerCase()) ||
          a.role?.toLowerCase().includes(search.toLowerCase()) ||
          a.company?.toLowerCase().includes(search.toLowerCase()),
      );

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Alumni Network</h1>
        <p className="text-white/50 mt-1">Connect with alumni from your institution</p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Total Alumni', value: alumni.length.toString(), icon: Users, color: 'text-white/70', bg: 'bg-white/5' },
          { label: 'Connected', value: Math.floor(alumni.length * 0.7).toString(), icon: Users, color: 'text-white/50', bg: 'bg-white/5' },
          { label: 'Companies', value: new Set(alumni.map((a: any) => a.company)).size.toString(), icon: Briefcase, color: 'text-white/40', bg: 'bg-white/5' },
          { label: 'Messages', value: '24', icon: MessageSquare, color: 'text-white/30', bg: 'bg-white/5' },
        ].map((stat, i) => (
          <motion.div
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.08 }}
            className="stat-card"
          >
            <div className="flex items-center justify-between mb-3">
              <div className={`w-10 h-10 rounded-lg ${stat.bg} flex items-center justify-center`}>
                <stat.icon className={`w-5 h-5 ${stat.color}`} />
              </div>
            </div>
            <p className="text-2xl font-bold text-white">{stat.value}</p>
            <p className="text-sm text-white/45 mt-0.5">{stat.label}</p>
          </motion.div>
        ))}
      </div>

      {/* Search */}
      <div className="relative max-w-md">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/35" />
        <input
          type="text"
          placeholder="Search alumni by name, company, or role..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="input-dark pl-10"
        />
      </div>

      {/* Alumni Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {filtered.length === 0 && (
          <p className="text-sm text-white/40 text-center py-8 col-span-full">No alumni found</p>
        )}
        {filtered.map((person: any, i: number) => {
          const initials = (person.name || '')
            .split(' ')
            .map((w: string) => w[0])
            .join('')
            .slice(0, 2)
            .toUpperCase();
          return (
            <motion.div
              key={person.id || i}
              initial={{ opacity: 0, y: 15 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: i * 0.06 }}
              className="card-dark p-5 hover:border-white/[0.12] transition-colors"
            >
              <div className="flex items-center gap-3 mb-3">
                <div className="w-11 h-11 rounded-full bg-accent/15 flex items-center justify-center text-accent-light text-sm font-bold">
                  {initials}
                </div>
                <div className="flex-1 min-w-0">
                  <h3 className="text-sm font-semibold text-white/90 truncate">{person.name}</h3>
                  <p className="text-xs text-white/40">Class of {person.year || person.graduationYear || '—'}</p>
                </div>
              </div>
              <p className="text-xs text-white/55 mb-4 flex items-center gap-1.5">
                <Briefcase className="w-3 h-3 flex-shrink-0" />
                {person.role || person.position || 'Role'} @ {person.company || '—'}
              </p>
              <div className="flex gap-2">
                <button className="flex-1 py-2 rounded-lg text-xs font-semibold bg-accent/10 text-accent-light border border-accent/20 hover:bg-accent/20 transition-all">
                  Connect
                </button>
                <button className="flex-1 py-2 rounded-lg text-xs font-semibold bg-white/[0.04] text-white/50 border border-white/[0.06] hover:bg-white/[0.06] transition-all">
                  Message
                </button>
              </div>
            </motion.div>
          );
        })}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import {
  CheckCircle2,
  XCircle,
  Calendar,
  TrendingUp,
  AlertTriangle,
  Loader2,
  Users,
  ChevronRight,
  Save,
} from 'lucide-react';
import { useApi } from '../../hooks/useApi';
import * as api from '../../lib/api';
import { useAuth } from '../../contexts/AuthContext';

export function Attendance() {
  const { user } = useAuth();
  const isFaculty = user?.role === 'faculty';

  const [view, setView] = useState<'overview' | 'history'>('overview');
  const [selectedCourse, setSelectedCourse] = useState<string | null>(null);
  const [markingDate, setMarkingDate] = useState(new Date().toISOString().split('T')[0]);
  const [entries, setEntries] = useState<Record<string, 'present' | 'absent' | 'late'>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const { data: studentData, isLoading: isStudentLoading, error: studentError } = useApi(
    () => !isFaculty ? api.fetchAttendance() : Promise.resolve(null),
    [isFaculty]
  );

  const { data: facultyCourses, isLoading: isCoursesLoading } = useApi(
    () => isFaculty ? api.fetchCourses() : Promise.resolve(null),
    [isFaculty]
  );

  const { data: courseStudents, isLoading: isStudentsLoading } = useApi(
    () => (isFaculty && selectedCourse) ? api.fetchCourseStudents(selectedCourse) : Promise.resolve(null),
    [isFaculty, selectedCourse]
  );

  // Initialize entries when students are loaded
  useEffect(() => {
    if (courseStudents?.students) {
      const initial: Record<string, 'present' | 'absent' | 'late'> = {};
      courseStudents.students.forEach((s: any) => {
        initial[s.id] = 'present';
      });
      setEntries(initial);
    }
  }, [courseStudents]);

  const handleMarkAttendance = async () => {
    if (!selectedCourse) return;
    setIsSubmitting(true);
    try {
      const markingEntries = Object.entries(entries).map(([studentId, status]) => ({
        studentId,
        status
      }));
      await api.markAttendance({
        courseId: selectedCourse,
        date: markingDate,
        entries: markingEntries
      });
      alert('Attendance marked successfully');
      setSelectedCourse(null);
    } catch (err: any) {
      alert(err.message || 'Failed to mark attendance');
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isStudentLoading || isCoursesLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-white/20 animate-spin" />
      </div>
    );
  }

  // Define faculty rendering logic
  if (isFaculty) {
    return (
      <div className="space-y-6">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
          <div>
            <h1 className="text-2xl font-bold text-white tracking-tight">Faculty Attendance</h1>
            <p className="text-white/40 mt-1">Manage and track student attendance for your courses</p>
          </div>
        </div>

        {!selectedCourse ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
            {facultyCourses?.courses?.map((course: any) => (
              <motion.div
                key={course.id}
                whileHover={{ scale: 1.02 }}
                className="card-dark p-6 cursor-pointer group"
                onClick={() => setSelectedCourse(course.id)}
              >
                <div className="flex justify-between items-start mb-4">
                  <div className="w-10 h-10 rounded bg-white/5 flex items-center justify-center">
                    <Users className="w-5 h-5 text-white/70" />
                  </div>
                  <span className="text-[10px] uppercase tracking-widest text-white/30 font-bold">{course.code}</span>
                </div>
                <h3 className="text-lg font-bold text-white mb-1">{course.name}</h3>
                <p className="text-xs text-white/40 mb-6">{course.enrolledStudents} Students Enrolled</p>
                <div className="flex items-center text-xs font-bold text-white/50 group-hover:text-white transition-colors">
                  Mark Attendance <ChevronRight className="w-4 h-4 ml-1" />
                </div>
              </motion.div>
            ))}
          </div>
        ) : (
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="card-dark p-0 overflow-hidden"
          >
            <div className="p-6 border-b border-white/5 flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <button 
                  onClick={() => setSelectedCourse(null)}
                  className="text-xs text-white/40 hover:text-white mb-2 flex items-center gap-1"
                >
                  ← Back to Courses
                </button>
                <h2 className="text-xl font-bold text-white">
                  {facultyCourses?.courses?.find((c: any) => c.id === selectedCourse)?.name}
                </h2>
              </div>
              <div className="flex items-center gap-3">
                <input 
                  type="date" 
                  value={markingDate}
                  onChange={(e) => setMarkingDate(e.target.value)}
                  className="bg-zinc-950 border border-zinc-800 text-xs text-white px-3 py-2 focus:outline-none focus:border-zinc-600"
                />
                <button
                  onClick={handleMarkAttendance}
                  disabled={isSubmitting}
                  className="bg-white text-black px-4 py-2 rounded text-xs font-bold flex items-center gap-2 hover:bg-zinc-200 disabled:opacity-50"
                >
                  {isSubmitting ? <Loader2 className="w-3 h-3 animate-spin" /> : <Save className="w-3 h-3" />}
                  Save Attendance
                </button>
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-white/[0.02] border-b border-white/5">
                    <th className="px-6 py-4 text-[10px] uppercase tracking-widest text-white/40 font-bold">Student Name</th>
                    <th className="px-6 py-4 text-[10px] uppercase tracking-widest text-white/40 font-bold text-center">Status</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-white/5">
                  {isStudentsLoading ? (
                    <tr><td colSpan={2} className="py-20 text-center"><Loader2 className="w-6 h-6 animate-spin mx-auto text-white/20" /></td></tr>
                  ) : courseStudents?.students?.length === 0 ? (
                    <tr><td colSpan={2} className="py-20 text-center text-white/20">No students enrolled in this course</td></tr>
                  ) : courseStudents?.students?.map((student: any) => (
                    <tr key={student.id} className="hover:bg-white/[0.01]">
                      <td className="px-6 py-4">
                        <div className="text-sm font-medium text-white">{student.fullName}</div>
                        <div className="text-[10px] text-white/30">{student.email}</div>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex items-center justify-center gap-2">
                          {(['present', 'absent', 'late'] as const).map((status) => (
                            <button
                              key={status}
                              onClick={() => setEntries(prev => ({ ...prev, [student.id]: status }))}
                              className={`px-3 py-1 rounded text-[10px] font-bold uppercase tracking-wider transition-all border ${
                                entries[student.id] === status
                                  ? 'bg-white text-black border-white'
                                  : 'bg-transparent text-white/20 border-white/5 hover:border-white/10 hover:text-white/40'
                              }`}
                            >
                              {status}
                            </button>
                          ))}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </motion.div>
        )}
      </div>
    );
  }

  // Student rendering (Original logic)
  if (isStudentLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-white/20 animate-spin" />
      </div>
    );
  }

  if (studentError) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-white/60 gap-3">
        <AlertTriangle className="w-8 h-8 text-amber-400" />
        <p className="text-sm">
          {typeof studentError === 'string' ? studentError : (studentError as any)?.message || 'Failed to load attendance'}
        </p>
      </div>
    );
  }

  const records = studentData?.attendance || studentData?.records || [];

  // Compute per-subject aggregation
  const subjectMap = new Map<string, { name: string; code: string; attended: number; total: number }>();
  const recentDays: { date: string; day: string; classes: { subject: string; status: string }[] }[] = [];
  const dayMap = new Map<string, { subject: string; status: string }[]>();

  for (const r of records) {
    const courseCode = r.course?.code || r.courseCode;
    const courseName = r.course?.name || r.courseName || r.subject;
    const key = courseCode || courseName || 'Unknown';

    if (!subjectMap.has(key)) {
      subjectMap.set(key, { name: courseName || key, code: courseCode || 'Unknown', attended: 0, total: 0 });
    }
    const s = subjectMap.get(key)!;
    s.total++;
    if (r.status === 'present' || r.status === 'late') s.attended++;

    // Group into days for history
    const fullDate = r.date || '';
    if (fullDate) {
      const dateStr = typeof fullDate === 'string' ? fullDate.split('T')[0] : fullDate;
      if (!dayMap.has(dateStr)) dayMap.set(dateStr, []);
      dayMap.get(dateStr)!.push({ subject: s.name, status: r.status });
    }
  }

  const subjects = Array.from(subjectMap.values()).map(s => ({
    ...s,
    status: (() => {
      const perc = s.total > 0 ? (s.attended / s.total) * 100 : 100;
      return perc < 65 ? 'danger' : perc < 75 ? 'warning' : 'safe';
    })(),
  }));

  // Build recent days (last 5)
  const sortedDates = Array.from(dayMap.keys()).sort().slice(-5).reverse();
  for (const d of sortedDates) {
    const dateObj = new Date(d);
    recentDays.push({
      date: dateObj.toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
      day: dateObj.toLocaleDateString('en-US', { weekday: 'short' }),
      classes: dayMap.get(d) || [],
    });
  }

  const overallAttended = subjects.reduce((s, sub) => s + sub.attended, 0);
  const overallTotal = subjects.reduce((s, sub) => s + sub.total, 0);
  const overallPerc = overallTotal > 0 ? Math.round((overallAttended / overallTotal) * 100) : 0;

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Attendance</h1>
          <p className="text-white/50 mt-1">Track your class attendance</p>
        </div>
        <div className="flex bg-surface-100 rounded-lg p-1">
          {(['overview', 'history'] as const).map((v) => (
            <button
              key={v}
              onClick={() => setView(v)}
              className={`px-4 py-1.5 rounded-md text-sm font-medium transition-all capitalize ${
                view === v ? 'bg-accent text-white' : 'text-white/50 hover:text-white/70'
              }`}
            >
              {v}
            </button>
          ))}
        </div>
      </div>

      {/* Overall Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Overall', value: `${overallPerc}%`, icon: TrendingUp, color: 'text-white', bg: 'bg-white/10' },
          { label: 'Present', value: `${overallAttended}`, icon: CheckCircle2, color: 'text-white/80', bg: 'bg-white/5' },
          { label: 'Absent', value: `${overallTotal - overallAttended}`, icon: XCircle, color: 'text-white/40', bg: 'bg-white/[0.02]' },
          { label: 'At Risk', value: subjects.filter(s => s.status === 'danger').length.toString(), icon: AlertTriangle, color: 'text-white/20', bg: 'bg-white/[0.01]' },
        ].map((stat, i) => (
          <motion.div
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.08 }}
            className="stat-card"
          >
            <div className="flex items-center justify-between mb-3">
              <div className={`w-10 h-10 rounded-lg ${stat.bg} flex items-center justify-center`}>
                <stat.icon className={`w-5 h-5 ${stat.color}`} />
              </div>
            </div>
            <p className="text-2xl font-bold text-white">{stat.value}</p>
            <p className="text-sm text-white/45 mt-0.5">{stat.label}</p>
          </motion.div>
        ))}
      </div>

      {view === 'overview' ? (
        <div className="card-dark p-5">
          <h3 className="text-base font-semibold text-white mb-4">Subject-wise Attendance</h3>
          <div className="space-y-4">
            {subjects.length === 0 && <p className="text-sm text-white/40 text-center py-6">No attendance records</p>}
            {subjects.map((sub, i) => {
              const perc = sub.total > 0 ? Math.round((sub.attended / sub.total) * 100) : 0;
              return (
                <motion.div
                  key={sub.code}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: i * 0.06 }}
                  className="flex items-center gap-4"
                >
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center justify-between mb-1.5">
                      <div>
                        <span className="text-sm font-medium text-white/85">{sub.name}</span>
                        <span className="text-xs text-white/35 ml-2">{sub.code}</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <span className="text-xs text-white/40">{sub.attended}/{sub.total}</span>
                        <span className={`text-sm font-bold ${
                          sub.status === 'danger' ? 'text-red-400' :
                          sub.status === 'warning' ? 'text-amber-400' : 'text-emerald-400'
                        }`}>{perc}%</span>
                      </div>
                    </div>
                    <div className="w-full h-2 bg-white/[0.06] rounded-full overflow-hidden">
                      <motion.div
                        initial={{ width: 0 }}
                        animate={{ width: `${perc}%` }}
                        transition={{ delay: 0.3 + i * 0.1, duration: 0.6 }}
                        className={`h-full rounded-full bg-white ${perc < 65 ? 'opacity-30' : perc < 85 ? 'opacity-60' : 'opacity-100'}`}
                      />
                    </div>
                  </div>
                </motion.div>
              );
            })}
          </div>
        </div>
      ) : (
        <div className="card-dark p-5">
          <h3 className="text-base font-semibold text-white mb-4">Recent Attendance</h3>
          <div className="space-y-4">
            {recentDays.length === 0 && <p className="text-sm text-white/40 text-center py-6">No recent records</p>}
            {recentDays.map((day, i) => (
              <motion.div
                key={day.date}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: i * 0.08 }}
              >
                <div className="flex items-center gap-2 mb-2">
                  <Calendar className="w-4 h-4 text-white/35" />
                  <span className="text-sm font-semibold text-white/70">{day.day}, {day.date}</span>
                </div>
                <div className="space-y-2 pl-6">
                  {day.classes.map((cls, j) => (
                    <div key={j} className="flex items-center gap-3 p-2.5 rounded-lg bg-white/[0.02]">
                      {cls.status === 'present' ? (
                        <CheckCircle2 className="w-4 h-4 text-white flex-shrink-0" />
                      ) : (
                        <XCircle className="w-4 h-4 text-white/20 flex-shrink-0" />
                      )}
                      <span className="text-sm text-white/75">{cls.subject}</span>
                      <span className={`ml-auto text-xs font-medium ${
                        cls.status === 'present' ? 'text-white/80' : 'text-white/20'
                      }`}>{cls.status}</span>
                    </div>
                  ))}
                </div>
              </motion.div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import {
  Bus,
  MapPin,
  Clock,
  Navigation,
  ChevronRight,
  Wifi,
  Loader2,
  AlertTriangle,
} from 'lucide-react';
import { useApi } from '../../hooks/useApi';
import * as api from '../../lib/api';

const busIconHtml = `<div style="background-color: #ffffff; padding: 6px; border-radius: 50%; color: black; display: flex; align-items: center; justify-content: center; box-shadow: 0 4px 6px -1px rgb(0 0 0 / 0.5); width: 28px; height: 28px;">
  <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M8 6v6"/><path d="M15 6v6"/><path d="M2 12h19.6"/><path d="M18 18h3s.5-1.7.8-2.8c.1-.4.2-.8.2-1.2 0-.4-.1-.8-.2-1.2l-1.4-5C20.1 6.8 19.1 6 18 6H4a2 2 0 0 0-2 2v10h3"/><circle cx="7" cy="18" r="2"/><circle cx="17" cy="18" r="2"/></svg>
</div>`;

const getBusIcon = (isActive: boolean) => {
  return new L.DivIcon({
    html: busIconHtml.replace('#ffffff', isActive ? '#ffffff' : '#a1a1aa'),
    className: 'custom-bus-icon',
    iconSize: [28, 28],
    iconAnchor: [14, 14],
  });
};

function MapUpdater({ center }: { center: [number, number] }) {
  const map = useMap();
  useEffect(() => {
    map.flyTo(center, map.getZoom(), { animate: true });
  }, [center, map]);
  return null;
}

export function BusTracking() {
  const [selectedRoute, setSelectedRoute] = useState<string | null>(null);
  const { data, isLoading, error } = useApi(() => api.fetchBusRoutes(), []);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-accent-light animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-white/60 gap-3">
        <AlertTriangle className="w-8 h-8 text-amber-400" />
        <p className="text-sm">{error}</p>
      </div>
    );
  }

  const routes = data?.routes || [];

  // Auto-select first route
  if (routes.length > 0 && selectedRoute === null) {
    setSelectedRoute(routes[0].id);
  }

  const activeRoute = routes.find((r: any) => r.id === selectedRoute);
  const stops = activeRoute ? (activeRoute.stops as any[]) : [];
  const activeBus = activeRoute?.buses?.[0];
  const currentStopName = activeBus?.currentLocation?.currentStop;

  // Determine stop statuses
  const stopsWithStatus = stops.map((stop: any) => {
    const currentIdx = stops.findIndex((s: any) => s.name === currentStopName);
    const thisIdx = stop.order - 1;
    let status = 'upcoming';
    if (currentIdx >= 0) {
      if (thisIdx < currentIdx) status = 'passed';
      else if (thisIdx === currentIdx) status = 'current';
    }
    return { ...stop, status };
  });

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-white">Bus Tracking</h1>
        <p className="text-white/50 mt-1">Real-time campus bus status</p>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {[
          { label: 'Active Buses', value: routes.reduce((s: number, r: any) => s + (r.buses?.length || 0), 0).toString(), icon: Bus },
          { label: 'Total Routes', value: routes.length.toString(), icon: Navigation },
          { label: 'Next Arrival', value: activeBus?.currentLocation ? '8 min' : '—', icon: Clock },
          { label: 'Live Tracking', value: 'ON', icon: Wifi },
        ].map((stat, i) => (
          <motion.div
            key={stat.label}
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: i * 0.08 }}
            className="card-dark p-6"
          >
            <div className="flex items-center justify-between mb-3">
              <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center">
                <stat.icon className="w-5 h-5 text-white/50" />
              </div>
            </div>
            <p className="text-2xl font-bold text-white tracking-tight">{stat.value}</p>
            <p className="text-[10px] uppercase font-bold tracking-widest text-white/30 mt-1">{stat.label}</p>
          </motion.div>
        ))}
      </div>

      {/* Live Map */}
      <div className="card-dark p-1 rounded-xl h-[400px] overflow-hidden relative z-0">
        <MapContainer 
          center={[12.9716, 77.5946]} 
          zoom={12} 
          style={{ height: '100%', width: '100%', borderRadius: '0.6rem' }}
        >
          <TileLayer
            attribution='&copy; <a href="https://carto.com/">CartoDB</a>'
            url="https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png"
          />
          {activeBus?.currentLocation && (
            <MapUpdater center={[activeBus.currentLocation.lat, activeBus.currentLocation.lng]} />
          )}
          {routes.map((route: any) => {
            const bus = route.buses?.[0];
            if (!bus?.currentLocation) return null;
            return (
              <Marker 
                key={route.id} 
                position={[bus.currentLocation.lat, bus.currentLocation.lng]}
                icon={getBusIcon(selectedRoute === route.id)}
              >
                <Popup className="custom-popup">
                  <div className="font-semibold text-black">{route.routeName}</div>
                  <div className="text-sm text-gray-800">Bus: {bus.registration || 'Unknown'}</div>
                  <div className="text-sm text-gray-800">Next Stop: {bus.currentLocation.nextStop || 'Arriving soon'}</div>
                </Popup>
              </Marker>
            );
          })}
        </MapContainer>
      </div>

      <div className="grid lg:grid-cols-5 gap-6">
        {/* Routes List */}
        <div className="lg:col-span-3 card-dark p-5">
          <div className="flex items-center gap-2 mb-4">
            <Bus className="w-5 h-5 text-white/50" />
            <h3 className="text-base font-semibold text-white">Bus Routes</h3>
          </div>
          <div className="space-y-3">
            {routes.map((route: any, i: number) => {
              const bus = route.buses?.[0];
              const isAtCampus = !bus?.currentLocation?.nextStop;
              const occupancy = bus?.currentLocation?.occupancy;

              return (
                <motion.button
                  key={route.id}
                  initial={{ opacity: 0, x: -10 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ delay: 0.2 + i * 0.06 }}
                  onClick={() => setSelectedRoute(route.id)}
                  className={`w-full text-left flex items-center gap-4 p-4 rounded-lg transition-all ${
                    selectedRoute === route.id
                      ? 'bg-accent/10 border border-accent/20'
                      : 'bg-white/[0.02] hover:bg-white/[0.04] border border-transparent'
                  }`}
                >
                  <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${
                    isAtCampus ? 'bg-white/10' : 'bg-white/5'
                  }`}>
                    <Bus className={`w-5 h-5 ${isAtCampus ? 'text-white' : 'text-white/40'}`} />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-white/90">{route.routeName}</p>
                    <p className="text-xs text-white/40 mt-0.5">{bus?.registration || '—'} · {bus?.driver || '—'}</p>
                  </div>
                  <div className="text-right flex-shrink-0">
                    {isAtCampus ? (
                      <span className="text-[10px] px-2 py-0.5 rounded border border-white/20 text-white font-bold">AT CAMPUS</span>
                    ) : (
                      <span className="text-[10px] px-2 py-0.5 rounded border border-white/10 text-white/40">EN ROUTE</span>
                    )}
                    {bus && <p className="text-[10px] text-white/20 mt-1">{occupancy || 0}/{bus.capacity} seats</p>}
                  </div>
                  <ChevronRight className="w-4 h-4 text-white/20 flex-shrink-0" />
                </motion.button>
              );
            })}
          </div>
        </div>

        {/* Route Detail / Stops */}
        <div className="lg:col-span-2 card-dark p-5">
          <div className="flex items-center gap-2 mb-4">
            <MapPin className="w-5 h-5 text-white/50" />
            <h3 className="text-base font-semibold text-white">Route Stops</h3>
          </div>
          <div className="space-y-1">
            {stopsWithStatus.map((stop: any, i: number) => (
              <motion.div
                key={i}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.3 + i * 0.06 }}
                className="flex items-center gap-3 py-2.5"
              >
                {/* Timeline */}
                <div className="flex flex-col items-center w-4 flex-shrink-0">
                  <div className={`w-3 h-3 rounded-full border-2 ${
                    stop.status === 'passed' ? 'bg-white/60 border-white/60' :
                    stop.status === 'current' ? 'bg-white border-white animate-pulse shadow-[0_0_10px_rgba(255,255,255,0.5)]' : 'bg-transparent border-white/20'
                  }`} />
                  {i < stopsWithStatus.length - 1 && (
                    <div className={`w-0.5 h-6 mt-0.5 ${
                      stop.status === 'passed' ? 'bg-white/20' : 'bg-white/5'
                    }`} />
                  )}
                </div>
                <div className="flex-1 min-w-0">
                  <p className={`text-sm ${
                    stop.status === 'current' ? 'font-bold text-white' :
                    stop.status === 'passed' ? 'text-white/30' : 'text-white/60'
                  }`}>{stop.name}</p>
                </div>
                <span className={`text-xs flex-shrink-0 ${
                  stop.status === 'current' ? 'text-white font-bold' : 'text-white/20'
                }`}>{stop.time}</span>
              </motion.div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

import {
  BookOpen,
  Clock,
  GraduationCap,
  TrendingUp,
  Calendar,
  Bell,
  ChevronRight,
  CheckCircle2,
  Loader2,
  AlertTriangle,
} from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../contexts/AuthContext';
import { useApi } from '../../hooks/useApi';
import * as api from '../../lib/api';

const ICON_MAP: Record<string, any> = {
  Clock, GraduationCap, BookOpen, TrendingUp,
};

export function Dashboard() {
  const navigate = useNavigate();
  const { user } = useAuth();
  const { data, isLoading, error } = useApi(() => api.fetchDashboard(), []);
  const { data: timetableData } = useApi(() => api.fetchTimetable(), []);
  const { data: notifData } = useApi(() => api.fetchNotifications(), []);

  const firstName = user?.fullName?.split(' ')[0] || 'Student';

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-white/50 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-white/60 gap-3">
        <AlertTriangle className="w-8 h-8 text-white/50" />
        <p className="text-sm">{error}</p>
      </div>
    );
  }

  const stats = data?.stats || {};

  // Today's schedule from timetable
  const today = new Date().toLocaleDateString('en-US', { weekday: 'long' });
  const schedule = (timetableData?.timetable?.[today] || []).map((cls: any) => ({
    time: cls.time?.split(' - ')[0] || cls.time,
    subject: cls.subject,
    room: cls.room,
    status: 'upcoming',
  }));

  // Recent activity from notifications
  const activity = (notifData?.notifications || []).slice(0, 5).map((n: any) => ({
    text: n.title + (n.body ? `: ${n.body}` : ''),
    time: new Date(n.createdAt).toLocaleDateString('en-US', { month: 'short', day: 'numeric' }),
    type: n.type === 'error' ? 'warning' : n.type === 'warning' ? 'warning' : n.type === 'success' ? 'success' : 'info',
  }));

  const statCards = [
    { label: 'Attendance', value: stats.attendancePercentage != null ? `${stats.attendancePercentage}%` : '—', change: '', iconKey: 'Clock' },
    { label: 'Courses', value: stats.courses ?? stats.totalCourses ?? '—', change: 'Enrolled', iconKey: 'GraduationCap' },
    { label: 'Events', value: stats.upcomingEvents ?? '—', change: 'Upcoming', iconKey: 'BookOpen' },
    { label: 'Notifications', value: stats.unreadNotifications ?? stats.pendingRequests ?? '—', change: 'Unread', iconKey: 'TrendingUp' },
  ];

  return (
    <div className="space-y-6">
      {/* Greeting */}
      <div>
        <h1 className="text-2xl font-bold text-white">Welcome back, {firstName}</h1>
        <p className="text-white/50 mt-1">Here's what's happening today.</p>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        {statCards.map((stat) => {
          const Icon = ICON_MAP[stat.iconKey] || Clock;
          return (
            <div key={stat.label} className="stat-card">
              <div className="flex items-center justify-between mb-3">
                <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center">
                  <Icon className="w-5 h-5 text-white/80" />
                </div>
                <span className="text-xs font-medium text-white/50">{stat.change}</span>
              </div>
              <p className="text-2xl font-bold text-white">{stat.value}</p>
              <p className="text-sm text-white/50 mt-0.5">{stat.label}</p>
            </div>
          );
        })}
      </div>

      {/* 2-Column Layout */}
      <div className="grid lg:grid-cols-5 gap-6">
        {/* Today's Schedule */}
        <div className="lg:col-span-3 card-dark p-5">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <Calendar className="w-5 h-5 text-white/70" />
              <h3 className="text-base font-semibold text-white">Today's Schedule</h3>
            </div>
            <button 
              onClick={() => navigate('/timetable')}
              className="text-xs text-white/50 hover:text-white font-medium flex items-center gap-1 transition-colors"
            >
              View All <ChevronRight className="w-3.5 h-3.5" />
            </button>
          </div>
          <div className="space-y-3">
            {schedule.length === 0 && (
              <p className="text-sm text-white/40 text-center py-6">No classes scheduled today</p>
            )}
            {schedule.map((cls: any, i: number) => (
              <div
                key={i}
                className={`flex items-center gap-4 p-3 rounded-lg transition-colors border ${
                  cls.status === 'ongoing'
                    ? 'bg-white/5 border-white/10'
                    : 'bg-transparent border-transparent hover:bg-white/[0.04]'
                }`}
              >
                <div className="text-sm font-medium text-white/50 w-20 flex-shrink-0">{cls.time}</div>
                <div className={`w-1 h-8 rounded-full flex-shrink-0 ${
                  cls.status === 'completed' ? 'bg-white' :
                  cls.status === 'ongoing' ? 'bg-white' : 'bg-white/20'
                }`} />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-white/90">{cls.subject}</p>
                  <p className="text-xs text-white/40">{cls.room}</p>
                </div>
                {cls.status === 'completed' && <CheckCircle2 className="w-4 h-4 text-white flex-shrink-0" />}
                {cls.status === 'ongoing' && (
                  <span className="px-2 py-0.5 rounded text-[10px] bg-white text-black font-bold">LIVE</span>
                )}
              </div>
            ))}
          </div>
        </div>

        {/* Recent Activity */}
        <div className="lg:col-span-2 card-dark p-5">
          <div className="flex items-center gap-2 mb-4">
            <Bell className="w-5 h-5 text-white/70" />
            <h3 className="text-base font-semibold text-white">Recent Activity</h3>
          </div>
          <div className="space-y-3">
            {activity.length === 0 && (
              <p className="text-sm text-white/40 text-center py-6">No recent activity</p>
            )}
            {activity.map((item: any, i: number) => (
              <div
                key={i}
                className="flex items-start gap-3 p-3 rounded-lg bg-transparent hover:bg-white/[0.04] transition-colors"
              >
                <div className="w-2 h-2 rounded-full mt-1.5 flex-shrink-0 bg-white/50" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm text-white/80">{item.text}</p>
                  <p className="text-xs text-white/35 mt-0.5">{item.time}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { motion } from 'framer-motion';
import {
  Calendar,
  MapPin,
  Users,
  Search,
  Loader2,
  AlertTriangle,
  X,
  FileEdit,
  Trash2,
  Plus
} from 'lucide-react';
import { AnimatePresence } from 'framer-motion';
import { useApi } from '../../hooks/useApi';
import { useAuth } from '../../contexts/AuthContext';
import * as api from '../../lib/api';

const categoryColors: Record<string, string> = {
  tech: 'border-white/10 text-white/40',
  social: 'border-white/20 text-white/60',
  sports: 'border-white/30 text-white/80',
  academic: 'border-white/25 text-white/70',
  cultural: 'border-white/15 text-white/50',
};

export function Events() {
  const { user } = useAuth();
  const isAdmin = user?.role === 'admin';
  const [search, setSearch] = useState('');
  const [filter, setFilter] = useState('all');
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [isRegistering, setIsRegistering] = useState(false);
  const [isEventModalOpen, setIsEventModalOpen] = useState(false);
  const [editingEvent, setEditingEvent] = useState<any>(null);
  const { data, isLoading, error, refetch } = useApi(() => api.fetchEvents(), []);

  if (isLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <Loader2 className="w-8 h-8 text-white/20 animate-spin" />
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex flex-col items-center justify-center h-64 text-white/60 gap-3">
        <AlertTriangle className="w-8 h-8 text-white/40" />
        <p className="text-sm">{error}</p>
      </div>
    );
  }

  const allEvents = data?.events || [];
  const categories = ['all', ...new Set(allEvents.map((e: any) => e.category || 'other'))];

  const filtered = allEvents.filter((e: any) => {
    const matchesSearch = !search || e.title?.toLowerCase().includes(search.toLowerCase());
    const matchesFilter = filter === 'all' || e.category === filter;
    return matchesSearch && matchesFilter;
  });

  return (
    <div className="space-y-6">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-white">Events</h1>
          <p className="text-white/50 mt-1">Discover campus events and activities</p>
        </div>
        {isAdmin && (
          <button 
            onClick={() => { setEditingEvent(null); setIsEventModalOpen(true); }}
            className="bg-white text-black px-4 py-2 rounded-lg text-xs font-bold hover:bg-zinc-200 transition-all flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            Create Event
          </button>
        )}
      </div>

      {/* Search & Filter */}
      <div className="flex flex-col sm:flex-row gap-3">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-white/35" />
