                </div>
                <div className="flex items-center gap-2 text-xs text-white/45">
                  <Users className="w-3.5 h-3.5" />
                  <span>{event.attendees} attending</span>
                </div>
              </div>
              <div className="flex gap-2 mt-4">
                <button 
